#include <cmath>

#define F 4
#define C 4
#define H 2
#define W 2
#define CTS 1024
#define SLOTS 4096

float data[F][C][H][W];
float ciphertexts[CTS][SLOTS];
float ciphertexts1[CTS][SLOTS];
float ciphertexts2[CTS][SLOTS];

// The schedules here come from CodegenTest.Conv2dNoInterchangeManySchedulesTest

// Helper for floord (floor division)
int floord(int n, int d) {
  if (d == 0) return 0;
  return floor((double)n / d);
}

void S(int f, int c, int h, int w, int ct, int slot) {
  if (f < 0 || f >= F || c < 0 || c >= C || h < 0 || h >= H || w < 0 ||
      w >= W || ct < 0 || ct >= CTS || slot < 0 || slot >= SLOTS) {
    return;
  }
  ciphertexts[ct][slot] = data[f][c][h][w];
}

void S1(int f, int c, int h, int w, int ct, int slot) {
  if (f < 0 || f >= F || c < 0 || c >= C || h < 0 || h >= H || w < 0 ||
      w >= W || ct < 0 || ct >= CTS || slot < 0 || slot >= SLOTS) {
    return;
  }
  ciphertexts1[ct][slot] = data[f][c][h][w];
}

void S2(int f, int c, int h, int w, int ct, int slot) {
  if (f < 0 || f >= F || c < 0 || c >= C || h < 0 || h >= H || w < 0 ||
      w >= W || ct < 0 || ct >= CTS || slot < 0 || slot >= SLOTS) {
    return;
  }
  ciphertexts2[ct][slot] = data[f][c][h][w];
}

